        if (card != null) {
            card.settings.mediaPlaybackRequiresUserGesture = !soundPlayer.config.autoplay
            val serverUrl = server.baseUrl()
            val injectedScript = """
                <script>
                    (function() {
                        var serverUrl = '$serverUrl';
                        window.AnkiDroid = { baseUrl: serverUrl };
                        var originalFetch = window.fetch;
                        window.fetch = function(input, init) {
                            if (typeof input === 'string' && (input.startsWith('/_anki/') || input.startsWith('/jsapi/'))) {
                                input = serverUrl + input.substring(1);
                            }
                            return originalFetch(input, init);
                        };
                        var originalOpen = window.XMLHttpRequest.prototype.open;
                        window.XMLHttpRequest.prototype.open = function(method, url) {
                            if (typeof url === 'string' && (url.startsWith('/_anki/') || url.startsWith('/jsapi/'))) {
                                url = serverUrl + url.substring(1);
                            }
                            return originalOpen.apply(this, arguments);
                        };
                    })();
                </script>
            """.trimIndent()
            card.loadDataWithBaseURL(
                baseUrl,
                injectedScript + content,
                "text/html",
                null,
                null
            )
        }
    }
